var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"배터리 LOW. 전투 한계시간 초과.","JPN":"バッテリーLOW。戦闘限界時間超過。","ENG":"Low battery. Combat time limit exceeded.","TWN":"電池電量過低，超過戰鬥時限。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JANUS_FAW_NULL_NULL","text":{"KOREA":"잠시 후 작동이 정지됩니다.","JPN":"まもなく動作停止します。","ENG":"System will shut down momentarily.","TWN":"稍後將停止運行。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"JANUS_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"회장~ 적들이 끝도 없이 몰려들어 와~","JPN":"かいちょ～敵を倒しても倒しても湧いてくるよぉ～。","ENG":"There's no end to them, President!","TWN":"會長~敵人源源不斷~"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"자율방어 시스템도 곧 무너지겠어. 후퇴해야 해.","JPN":"自律防御システムもそろそろ持たない、撤退しないと。","ENG":"The ADS is going to go down soon. We have to fall back.","TWN":"自主防禦系統馬上就要崩潰了，必須趕緊撤離。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L9_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"후퇴할 수 없어요.","JPN":"撤退はできません。","ENG":"We can't.","TWN":"不能撤離。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L10_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"왜애~","JPN":"なんでよぉ～。","ENG":"Why not?","TWN":"為什麼~"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"우리가 여기서 물러서면 학생들은 무방비 상태가 되겠죠.","JPN":"私たちがここで退いたら生徒たちが無防備になります。","ENG":"If we do, the students here will be defenseless.","TWN":"如果我們在這裡撤離，學生們就會變成無防備狀態。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"어떻게든 지원이 올 때까지 버텨야 해요.","JPN":"どうにか応援が来るまで持ちこたえるべきです。","ENG":"We must hold our ground until reinforcements arrive.","TWN":"不管怎樣也要堅持到支援到來。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"우음...... 그치만 지원이 올 시간은 한참 지났는걸.","JPN":"ううん……でも応援部隊が来る時間はとっくに過ぎてるよ。","ENG":"Hmm... But they should have been here ages ago.","TWN":"嗚嗚……可是距離支援應該到達的時間已經過去很久了啊。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"침식파가 너무 강해서 선생님들이랑 연락도 안 되고~","JPN":"侵食波が強すぎて先生たちとも連絡できないしねぇ。","ENG":"And the Corruption ray is too strong to get into touch with the teachers.","TWN":"侵蝕波太強，也沒辦法跟老師們聯繫~"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"실망하지 마세요. 지원은 반드시 옵니다.","JPN":"諦めないでください。応援は必ず来ます。","ENG":"Don't be disappointed. Reinforcements are sure to come.","TWN":"別沮喪，支援一定會到的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"아카데미는 학생들을 버리지 않으니까요.","JPN":"アカデミーは生徒を見捨てることはしません。","ENG":"The Academy never forsakes its students.","TWN":"學院不會放棄學生的。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"본대가 통신이 끊긴 상황을 확인하면......","JPN":"本隊が通信が切れた状態を確認しているなら……","ENG":"Once they realize the comms have been cut off—","TWN":"如果營地發現通信中斷……"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L19_1","type":"dialog","speaker":"CHAIR_SCHOOL_NULL_NULL","text":{"KOREA":"저건......! 회장, 3종 침식체야!","JPN":"あれは……！　会長、第3種侵食体だよ！","ENG":"Look! That's a Category 3!","TWN":"那是......！3類侵蝕體！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"CHAIR_SCHOOL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PRESIDENT_SCHOOL_NULL_NULL","text":{"KOREA":"제가 상대하겠습니다! 이디스는 다른 학생들을 지켜 주세요!","JPN":"私が行きます！　イーディスは生徒たちを守ってください！","ENG":"I'll take care of it! Please protect the students, Edith!","TWN":"我來對付！伊蒂絲你去保護其他學生！"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"PRESIDENT_SCHOOL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"어이쿠, 머리 조심하세요.","JPN":"おっと、頭に気をつけてくださいね。","ENG":"Oopsie, watch your head.","TWN":"哎喲，小心頭部。"},"stage":{"bg":"COUNTERSIDE_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};